WITH FirstTransactionDates AS (
  SELECT account_id, MIN(date) AS firstTransactionDate FROM trans GROUP BY account_id 
), FirstLoanDates AS (
  SELECT account_id, MIN(date) AS firstLoanDate FROM loan GROUP BY account_id 
) 
SELECT ft.account_id, JULIANDAY(ft.firstTransactionDate) - JULIANDAY(fl.firstLoanDate) AS dateDifference 
FROM FirstTransactionDates ft JOIN FirstLoanDates fl ON ft.account_id = fl.account_id;

SELECT source, SUM(amount) AS totalAmount 
FROM income 
GROUP BY source;

SELECT * FROM account
LEFT JOIN loan ON account.account_id = loan.account_id
WHERE loan.date BETWEEN '1995-01-01' AND '1995-12-31';
